import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DwYrYzXn.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"packages/ticker/CHANGELOG.md","filePath":"packages/ticker/CHANGELOG.md"}'),r={name:"packages/ticker/CHANGELOG.md"};function d(n,e,l,c,s,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to the <code>@magmacomputing/tempo-plugin-ticker</code> project will be documented in this file.</p><h2 id="_1-0-4-2026-06-11" tabindex="-1">[1.0.4] - 2026-06-11 <a class="header-anchor" href="#_1-0-4-2026-06-11" aria-label="Permalink to &quot;[1.0.4] - 2026-06-11&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Label Identification</strong>: Added the <code>label?: string</code> property to <code>Ticker.Options</code>. Developers can now easily tag and group tickers without needing external memory-tracking structures (like <code>WeakMap</code>). This label is natively exposed on <code>Tempo.tickers</code> snapshots.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>NPM Registry Metadata</strong>: Explicitly added <code>README.md</code>, <code>CHANGELOG.md</code>, and <code>LICENSE</code> to the <code>files</code> array in <code>package.json</code> to ensure the npmjs.com registry correctly renders package documentation.</li><li><strong>Test Integrity</strong>: Updated internal test fixtures to correctly align with Tempo Core&#39;s standard capitalization and the recent rename of the <code>period</code> term to <code>timeOfDay</code>.</li></ul><h2 id="_1-0-3-2026-06-07" tabindex="-1">[1.0.3] - 2026-06-07 <a class="header-anchor" href="#_1-0-3-2026-06-07" aria-label="Permalink to &quot;[1.0.3] - 2026-06-07&quot;">​</a></h2><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>Migrated licensing enforcement from <code>jose</code> to the native WebCrypto Tempo Core primitives.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Replaced all usage of the global <code>Date</code> object with the <code>instant()</code> temporal engine in the core validator to ensure timeline consistency.</li><li>Corrected test environment resolution boundaries that caused unhandled asynchronous Promise verification leaks.</li></ul><h2 id="_1-0-2-2026-06-06" tabindex="-1">[1.0.2] - 2026-06-06 <a class="header-anchor" href="#_1-0-2-2026-06-06" aria-label="Permalink to &quot;[1.0.2] - 2026-06-06&quot;">​</a></h2><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Centralized the CI/CD test sandboxing configuration to ensure consistent environment variables and licensing mocks across all workspaces.</li></ul><h2 id="_1-0-1-2026-06-04" tabindex="-1">[1.0.1] - 2026-06-04 <a class="header-anchor" href="#_1-0-1-2026-06-04" aria-label="Permalink to &quot;[1.0.1] - 2026-06-04&quot;">​</a></h2><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Resolved the &quot;Ghost-Trap&quot; architectural conflict that prevented validation when used with Tempo v3.0.0.</li><li>Decoupled <code>definePremiumPlugin</code> and cryptographic validation from the plugin bundle. Licensing engine state and references are now directly imported from the Tempo Core (<code>@magmacomputing/tempo/plugin</code>).</li><li>Removed the <code>@magmacomputing/tempo-plugin-core</code> bundled <code>devDependency</code> to prevent duplicate initialization.</li></ul><h2 id="_1-0-0-2026-06-01" tabindex="-1">[1.0.0] - 2026-06-01 <a class="header-anchor" href="#_1-0-0-2026-06-01" aria-label="Permalink to &quot;[1.0.0] - 2026-06-01&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial release of the Ticker plugin.</li><li>A highly accurate and CPU-efficient periodic timer designed as an alternative to native <code>setInterval</code>.</li><li>Features pause, resume, reset, and configurable jitter compensation.</li><li>Supports both <code>EventEmitter</code> and callback-based listener patterns.</li><li>Implements the <code>v3.0.0</code> Tempo Core Licensing API via cryptographic JSON Web Signatures (JWS).</li></ul>',21)])])}const p=a(r,[["render",d]]);export{m as __pageData,p as default};
